import React, { ReactNode } from 'react';

// --- Contexts ---
import { AppProvider, AppContext } from './contexts/AppContext';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import { I18nProvider } from './contexts/I18nContext';
import { UIProvider, useUI } from './contexts/UIContext';

// --- Layout & Shared Components ---
import { Sidebar } from './components/layout/Sidebar';
import { Toast } from './components/shared/Toast';
import { LoadingSpinner } from './components/shared/LoadingSpinner';
import { ExclamationTriangleIcon } from './components/Icons';

// --- Modals ---
import { EditBankModal } from './components/modals/EditBankModal';
import { EditChurchModal } from './components/modals/EditChurchModal';
import { ManualIdModal } from './components/modals/ManualIdModal';
import { ConfirmDeleteModal } from './components/modals/ConfirmDeleteModal';
import { ManualMatchModal } from './components/modals/ManualMatchModal';
import { SaveReportModal } from './components/modals/SaveReportModal';
import { SearchFiltersModal } from './components/modals/SearchFiltersModal';
import { DivergenceConfirmationModal } from './components/modals/DivergenceConfirmationModal';
import { PaymentModal } from './components/modals/PaymentModal';
import { FilePreprocessorModal } from './components/modals/FilePreprocessorModal';
import { SmartEditModal } from './components/modals/SmartEditModal';

// --- Views ---
import { AuthView } from './views/AuthView';
import { DashboardView } from './views/DashboardView';
import { UploadView } from './views/UploadView';
import { RegisterView } from './views/RegisterView';
import { ReportsView } from './views/ReportsView';
import { SettingsView } from './views/SettingsView';
import { SearchView } from './views/SearchView';
import { SavedReportsView } from './views/SavedReportsView';
import { AdminView } from './views/AdminView';
import { SmartAnalysisView } from './views/SmartAnalysisView';

// --- Error Boundary ---
interface ErrorBoundaryProps {
  children?: ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
}

class ErrorBoundary extends React.Component<ErrorBoundaryProps, ErrorBoundaryState> {
  public state: ErrorBoundaryState = {
    hasError: false
  };

  static getDerivedStateFromError(error: any): ErrorBoundaryState {
    return { hasError: true };
  }

  componentDidCatch(error: any, errorInfo: any) {
    console.error("Uncaught error:", error, errorInfo);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex items-center justify-center bg-brand-bg p-4">
            <div className="bg-white p-8 rounded-2xl shadow-card text-center max-w-md border border-red-100">
                <div className="mx-auto w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mb-4">
                    <ExclamationTriangleIcon className="w-6 h-6 text-red-500" />
                </div>
                <h2 className="text-xl font-display font-bold text-brand-graphite mb-2">Algo deu errado</h2>
                <p className="text-slate-500 mb-6">Ocorreu um erro inesperado. Tente recarregar a página.</p>
                <button onClick={() => window.location.reload()} className="px-6 py-2.5 bg-brand-blue text-white rounded-xl font-semibold hover:bg-blue-600 transition-colors shadow-lg shadow-blue-500/20">Recarregar</button>
            </div>
        </div>
      );
    }

    return (this as any).props.children;
  }
}

// --- Modals Render Helper ---
const ModalsRenderer = () => {
    const context = React.useContext(AppContext);
    if (!context) return null;

    const {
        editingBank, 
        editingChurch, 
        manualIdentificationTx, 
        bulkIdentificationTxs,
        deletingItem, 
        manualMatchState, 
        savingReportState, 
        isSearchFiltersOpen, 
        divergenceConfirmation,
        isPaymentModalOpen,
        pendingTraining,
        setPendingTraining,
        handleTrainingSuccess,
        smartEditTarget
    } = context;

    if (!editingBank && !editingChurch && !manualIdentificationTx && !bulkIdentificationTxs && !deletingItem && !manualMatchState && !savingReportState && !isSearchFiltersOpen && !divergenceConfirmation && !isPaymentModalOpen && !pendingTraining && !smartEditTarget) {
        return null;
    }

    return (
        <>
            {editingBank && <EditBankModal />}
            {editingChurch && <EditChurchModal />}
            {(manualIdentificationTx || bulkIdentificationTxs) && <ManualIdModal />}
            {deletingItem && <ConfirmDeleteModal />}
            {manualMatchState && <ManualMatchModal />}
            {savingReportState && <SaveReportModal />}
            {isSearchFiltersOpen && <SearchFiltersModal />}
            {divergenceConfirmation && <DivergenceConfirmationModal />}
            {isPaymentModalOpen && <PaymentModal />}
            {pendingTraining && (
                <FilePreprocessorModal 
                    onClose={() => setPendingTraining(null)}
                    initialFile={pendingTraining}
                    onSuccess={handleTrainingSuccess}
                />
            )}
            {smartEditTarget && <SmartEditModal />}
        </>
    );
};

// --- View Router ---
const ViewRouter = () => {
    const { activeView } = useUI();
    const { user } = useAuth();

    // Robust check: Lowercase comparison to ensure access matches regardless of casing
    const isAdmin = user?.email?.toLowerCase().trim() === 'identificapix@gmail.com';

    switch (activeView) {
        case 'dashboard': return <DashboardView />;
        case 'upload': return <UploadView />;
        case 'cadastro': return <RegisterView />;
        case 'reports': return <ReportsView />;
        case 'search': return <SearchView />;
        case 'savedReports': return <SavedReportsView />;
        case 'settings': return <SettingsView />;
        case 'smart_analysis': return <SmartAnalysisView />;
        case 'admin': return isAdmin ? <AdminView /> : <DashboardView />;
        default: return <DashboardView />;
    }
};

// --- Main Application Layout ---
const MainAppContent = () => {
    const { isLoading, toast } = useUI();
    const context = React.useContext(AppContext);

    if (!context) return <LoadingSpinner />;

    const { initialDataLoaded } = context;

    if (!initialDataLoaded) {
        return (
            <div className="h-[100dvh] w-screen flex items-center justify-center bg-brand-deep">
                <LoadingSpinner />
            </div>
        );
    }

    return (
        <div className="flex h-[100dvh] bg-[#F1F5F9] dark:bg-[#0B1120] font-sans overflow-hidden">
            {/* Sidebar is fixed height, main content scrolls */}
            <Sidebar />

            <main className="flex-1 flex flex-col min-w-0 overflow-hidden relative">

                {/* Alterado padding de p-6/p-8 para p-2/p-3 para maximizar espaço */}
                <div className="flex-1 overflow-y-auto p-2 md:p-3 scroll-smooth z-10 custom-scrollbar relative">
                    <div className="max-w-[1920px] mx-auto h-full flex flex-col relative z-10">
                        {isLoading ? (
                            <div className="flex-1 flex items-center justify-center">
                                <LoadingSpinner />
                            </div>
                        ) : (
                            <div className="animate-fade-in h-full">
                                <ViewRouter />
                            </div>
                        )}
                    </div>
                </div>
            </main>

            {toast && <Toast message={toast.message} type={toast.type} />}
            <ModalsRenderer />
        </div>
    );
};

// --- App Controller ---
const AppController: React.FC = () => {
    const { session, loading } = useAuth();

    if (loading) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-[#051024]">
                <LoadingSpinner />
            </div>
        );
    }

    if (!session) {
        return <AuthView />;
    }

    return (
        <ErrorBoundary>
            <UIProvider>
                <AppProvider>
                    <MainAppContent />
                </AppProvider>
            </UIProvider>
        </ErrorBoundary>
    );
}

export default function App() {
    return (
        <I18nProvider>
            <AuthProvider>
                <AppController />
            </AuthProvider>
        </I18nProvider>
    );
}

import React, { useContext, useMemo, useState, memo, useEffect, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { EditableReportTable } from '../components/reports/EditableReportTable';
import { SavedReportsView } from './SavedReportsView';
import { EmptyState } from '../components/EmptyState';
import { usePersistentState } from '../hooks/usePersistentState';
import { 
    DocumentDuplicateIcon, 
    PrinterIcon, 
    DocumentArrowDownIcon, 
    TrashIcon, 
    SearchIcon, 
    XMarkIcon, 
    UserPlusIcon, 
    SparklesIcon, 
    ChevronDownIcon, 
    ChevronRightIcon, 
    ChevronLeftIcon, 
    FloppyDiskIcon, 
    ChartBarIcon, 
    UploadIcon, 
    ArrowLeftOnRectangleIcon, 
    AdjustmentsHorizontalIcon, 
    BuildingOfficeIcon, 
    ExclamationTriangleIcon, 
    ArrowPathIcon, 
    CheckBadgeIcon, 
    BanknotesIcon
} from '../components/Icons';
import { formatCurrency, formatDate } from '../utils/formatters';
import { MatchResult, Language } from '../types';
import { parseDate, filterByUniversalQuery, normalizeString } from '../services/processingService';
import * as XLSX from 'xlsx';
import jsPDF from 'jspdf';
import autoTable from 'jspdf-autotable';

type SortDirection = 'asc' | 'desc';
interface SortConfig {
    key: string;
    direction: SortDirection;
}

const getNestedValue = (obj: any, path: string) => {
    return path.split('.').reduce((o, key) => (o && o[key] != null ? o[key] : null), obj);
};

// Componente Compacto de Métricas (Design Clean)
const CompactMetricsBar: React.FC<{ metrics: any, language: Language, isExpense: boolean }> = ({ metrics, language, isExpense }) => {
    if (isExpense) return null;

    return (
        <div className="flex items-center gap-2 text-[9px] font-medium text-slate-600 dark:text-slate-300 overflow-x-auto custom-scrollbar pb-0.5">
            {/* Total Geral - White Pill */}
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 whitespace-nowrap">
                <span className="font-bold text-slate-700 dark:text-slate-200">Total:</span>
                <span className="text-slate-600 dark:text-slate-400">{metrics.total.quantity}</span>
                <span className="text-slate-300 dark:text-slate-600 mx-0.5">|</span>
                <span className="font-mono font-bold text-slate-900 dark:text-white">{formatCurrency(metrics.total.value, language)}</span>
            </div>

            {/* Auto (Verde) - White Pill with Green Accent */}
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-100 dark:border-emerald-800 whitespace-nowrap">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
                <span className="text-emerald-700 dark:text-emerald-400">Auto: {metrics.auto.quantity}</span>
                <span className="font-mono font-bold text-emerald-600 dark:text-emerald-500">({metrics.auto.percentage.toFixed(0)}%)</span>
            </div>

            {/* Manual (Azul) - White Pill with Blue Accent */}
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 whitespace-nowrap">
                <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
                <span className="text-blue-700 dark:text-blue-400">Manual: {metrics.manual.quantity}</span>
                <span className="font-mono font-bold text-blue-600 dark:text-blue-500">({metrics.manual.percentage.toFixed(0)}%)</span>
            </div>

            {/* Pendente (Amarelo) - White Pill with Amber Accent */}
            {metrics.pending.quantity > 0 && (
                <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-amber-50 dark:bg-amber-900/20 border border-amber-100 dark:border-amber-800 whitespace-nowrap">
                    <ExclamationTriangleIcon className="w-3 h-3 text-amber-500" />
                    <span className="text-amber-700 dark:text-amber-400 font-bold">Pend: {metrics.pending.quantity}</span>
                    <span className="font-mono font-bold text-amber-600 dark:text-amber-500">({formatCurrency(metrics.pending.value, language)})</span>
                </div>
            )}
        </div>
