                const income = parseBrValue(row.income);
                const expense = parseBrValue(row.expense);
                return {
                    pos: index + 1,
                    name: row.churchName,
                    income,
                    expense,
                    balance: income - expense,
                    count: parseInt(row.count) || 0
                };
            });
    };

