                                return (
                                    <div key={bank.id} className="flex flex-col sm:flex-row sm:items-center justify-between p-2.5 bg-slate-50 hover:bg-slate-100 dark:bg-slate-900/30 rounded-xl border border-slate-200 dark:border-slate-700/50 hover:border-blue-200 transition-all gap-2 group/item">
