                                                >
                                                    <WrenchScrewdriverIcon className="w-3.5 h-3.5" />
                                                </button>
                                            )}
                                            <FileUploader
                                                id={`church-uploader-${church.id}`}
                                                title={t('upload.upload')}
                                                onFileUpload={(content, name, raw) => handleContributorsUpload(content, name, church.id)}
