                        className="flex items-center gap-2 px-6 py-3 bg-gradient-to-l from-[#051024] to-[#0033AA] hover:from-[#020610] hover:to-[#002288] text-white rounded-full font-bold text-[10px] uppercase tracking-widest shadow-2xl transition-all transform hover:-translate-y-1 active:translate-y-0 border border-white/10"
