            {isConfigModalOpen && (
                <InitialComparisonModal onClose={() => setIsConfigModalOpen(false)} />
            )}

            {isGmailOpen && (
                <GmailModal 
                    onClose={handleGmailClose} 
                    onSuccess={handleGmailSuccess} 
                />
            )}
        </div>
    );
};

