    return (
        <div className="flex flex-col h-full animate-fade-in gap-2 pb-1">

            <div className="flex-shrink-0 flex flex-col xl:flex-row xl:items-center justify-between gap-4 px-1 mt-1 min-h-[40px]">
                <div className="flex items-center gap-4">
                    <h2 className="text-xl font-black text-slate-900 dark:text-white tracking-tight leading-none whitespace-nowrap">
                        {t('smart_analysis.title')}
                    </h2>

                    <div className={`relative ${activeTemplate === 'manual_structure' ? 'opacity-50 pointer-events-none' : ''}`}>
                        <div className="absolute inset-y-0 left-0 pl-2.5 flex items-center pointer-events-none">
                            <CircleStackIcon className="w-3.5 h-3.5 text-slate-500 dark:text-slate-400" />
                        </div>
                        <select 
                            value={selectedReportId}
                            onChange={(e) => setSelectedReportId(e.target.value)}
                            className="pl-7 pr-7 py-1.5 bg-slate-100/50 dark:bg-slate-900/50 border border-slate-200 dark:border-slate-700 rounded-full text-[10px] font-bold text-slate-700 dark:text-slate-200 focus:ring-1 focus:ring-violet-500 outline-none cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800 transition-all shadow-sm uppercase tracking-wide"
                        >
                            {sourceOptions.length === 0 && <option disabled>Nenhum dado</option>}
                            {sourceOptions.map(opt => (
                                <option key={opt.id} value={opt.id}>{opt.label}</option>
                            ))}
                        </select>
                    </div>
                </div>

                {/* UNIFIED COMMAND CAPSULE */}
                <div className="flex items-center h-9 bg-gradient-to-r from-blue-600 via-[#051024] to-blue-600 rounded-full shadow-lg border border-white/20 overflow-hidden overflow-x-auto custom-scrollbar p-0.5">

                    <UnifiedButton 
                        onClick={() => setActiveTemplate('ranking')}
                        isActive={activeTemplate === 'ranking'}
                        icon={TrophyIcon}
                        label="Ranking"
                    />
                    <UnifiedButton 
                        onClick={() => setActiveTemplate('manual_structure')}
                        isActive={activeTemplate === 'manual_structure'}
                        icon={TableCellsIcon}
                        label="Manual"
                    />

                    <UnifiedButton 
                        onClick={handleSortRows}
                        icon={ArrowPathIcon}
                        label="Ordernar"
                    />
                    <UnifiedButton 
                        onClick={handlePrint}
                        icon={PrinterIcon}
                        label="Imprimir"
                    />
                    <UnifiedButton 
                        onClick={handleDownload}
                        icon={DocumentArrowDownIcon}
                        label="Excel"
                    />
                    <UnifiedButton 
                        onClick={handleSave}
                        icon={FloppyDiskIcon}
                        label="Salvar"
                        isActive={true} 
                        isLast={true}
                    />
                </div>
            </div>

            {/* Main Content Area */}
            <div className="flex-1 flex flex-col bg-white dark:bg-slate-900 rounded-2xl shadow-card border border-slate-200 dark:border-slate-700 overflow-hidden relative min-h-0">
                <div className="absolute top-0 right-0 w-64 h-64 bg-violet-500/5 rounded-full blur-[80px] pointer-events-none -mr-20 -mt-20"></div>

                {activeTemplate ? (
                    <div className="flex-1 flex flex-col p-3 relative z-10 overflow-hidden">
