                            >
                                <PlusCircleIcon className="w-3 h-3" />
                                <span>Adicionar Linha</span>
                            </button>
                        </div>

                        <div className="flex-1 min-h-0 w-full bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl shadow-sm overflow-hidden flex flex-col mb-2">
