                {/* UNIFIED COMMAND CAPSULE */}
                <div className="flex items-center h-9 bg-gradient-to-r from-blue-600 via-[#051024] to-blue-600 rounded-full shadow-lg border border-white/20 overflow-hidden overflow-x-auto custom-scrollbar p-0.5 w-full md:w-auto">

                    <UnifiedButton 
                        label="Igrejas" 
                        icon={BuildingOfficeIcon} 
