                )}

                {activeTab === 'unidentified' && (
                    <div className="flex-1 min-h-0 flex flex-col animate-fade-in">
                        {unidentifiedData.length > 0 ? (
                            <ReportGroup churchId="unidentified" results={unidentifiedData} reportType="income" defaultOpen={true} />
