                        <div className="px-6 py-4 bg-slate-50 dark:bg-slate-900 border-t border-slate-200 dark:border-slate-700 flex justify-end">
                            <button onClick={() => setShowDiagModal(false)} className="px-5 py-2 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-800 rounded-full transition-colors uppercase">Fechar</button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useContext, useState, useMemo, useEffect } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { ResultsTable } from '../components/ResultsTable';
import { EmptyState } from '../components/EmptyState';
import { SearchIcon, AdjustmentsHorizontalIcon, PrinterIcon, FloppyDiskIcon, CheckCircleIcon, XCircleIcon, CircleStackIcon, XMarkIcon } from '../components/Icons';
import { filterByUniversalQuery, parseDate, normalizeString } from '../services/processingService';
import { formatCurrency, formatDate } from '../utils/formatters';

const ITEMS_PER_PAGE = 50;

export const SearchView: React.FC = () => {
    // ... (Mantém hooks e lógica existente)
    const { 
        allHistoricalResults, 
        savedReports,
        openManualIdentify, 
        loadingAiId, 
        searchFilters,
        openSearchFilters,
        setSearchFilters,
        saveFilteredReport,
    } = useContext(AppContext);

    const { setActiveView } = useUI();
    const { t, language } = useTranslation();
    const [query, setQuery] = useState('');
    const [currentPage, setCurrentPage] = useState(1);

    const activeFilterCount = useMemo(() => {
        let count = 0;
        if (searchFilters.dateRange.start || searchFilters.dateRange.end) count++;
        if (searchFilters.valueFilter.operator !== 'any') count++;
        if (searchFilters.filterBy === 'church' && searchFilters.churchIds.length > 0) count++;
        if (searchFilters.filterBy === 'contributor' && searchFilters.contributorName.trim()) count++;
        if (searchFilters.transactionType !== 'all') count++;
        if (searchFilters.reconciliationStatus !== 'all') count++;
        return count;
    }, [searchFilters]);

    // ... (Lógica de filtragem sourceData, filteredResults, summary mantida) ...
    const sourceData = useMemo(() => {
        if (searchFilters.reportId) {
            const report = savedReports.find(r => r.id === searchFilters.reportId);
            return report?.data?.results || [];
        }
        return allHistoricalResults;
    }, [searchFilters.reportId, savedReports, allHistoricalResults]);

    const filteredResults = useMemo(() => {
        let results = [...sourceData];

        if (searchFilters.transactionType === 'income') {
            results = results.filter(r => r.transaction.amount > 0);
        } else if (searchFilters.transactionType === 'expenses') {
            results = results.filter(r => r.transaction.amount < 0);
        }

        switch (searchFilters.reconciliationStatus) {
            case 'confirmed_any':
                results = results.filter(r => r.status === 'IDENTIFICADO');
                break;
            case 'unconfirmed':
                results = results.filter(r => r.status === 'NÃO IDENTIFICADO');
                break;
            case 'confirmed_auto':
                results = results.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
                break;
            case 'confirmed_manual':
                 results = results.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
                break;
        }

        if (searchFilters.filterBy === 'contributor' && searchFilters.contributorName.trim()) {
            results = results.filter(r => filterByUniversalQuery(r, searchFilters.contributorName));
        }

        if (searchFilters.filterBy === 'church' && searchFilters.churchIds.length > 0) {
            results = results.filter(r => searchFilters.churchIds.includes(r.church.id));
        }

        const startDate = searchFilters.dateRange.start ? new Date(searchFilters.dateRange.start).getTime() : null;
        const endDate = searchFilters.dateRange.end ? new Date(searchFilters.dateRange.end).getTime() + 86400000 : null;
        if (startDate || endDate) {
            results = results.filter(r => {
                const itemDate = parseDate(r.transaction.date)?.getTime();
                if (!itemDate) return false;
                if (startDate && itemDate < startDate) return false;
                if (endDate && itemDate >= endDate) return false;
                return true;
            });
        }

        const { operator, value1, value2 } = searchFilters.valueFilter;
        if (operator !== 'any' && value1 !== null) {
            results = results.filter(r => {
                const amount = r.transaction.amount;
                switch (operator) {
                    case 'exact': return amount === value1;
                    case 'gt': return amount > value1;
                    case 'lt': return amount < value1;
                    case 'between': return value2 !== null && amount >= value1 && amount <= value2;
                    default: return true;
                }
            });
        }

        if (query.trim()) {
            results = results.filter(r => filterByUniversalQuery(r, query));
        }

        return results;
    }, [query, sourceData, searchFilters]);

    const summary = useMemo(() => {
        const income = filteredResults.filter(r => r.transaction.amount > 0).reduce((sum, r) => sum + r.transaction.amount, 0);
        const expenses = filteredResults.filter(r => r.transaction.amount < 0).reduce((sum, r) => sum + r.transaction.amount, 0);
        const identified = filteredResults.filter(r => r.status === 'IDENTIFICADO').length;
        return {
            totalCount: filteredResults.length,
            income,
            expenses,
            identified,
            unidentified: filteredResults.length - identified,
        };
    }, [filteredResults]);

    useEffect(() => {
        setCurrentPage(1);
    }, [query, searchFilters]);

    const totalPages = Math.ceil(filteredResults.length / ITEMS_PER_PAGE);
    const paginatedResults = useMemo(() => {
        const start = (currentPage - 1) * ITEMS_PER_PAGE;
        return filteredResults.slice(start, start + ITEMS_PER_PAGE);
    }, [filteredResults, currentPage]);

    const handleSave = () => {
        saveFilteredReport(filteredResults);
    };

    const handlePrint = () => {
        const printWindow = window.open('', '_blank');
        if (!printWindow) return;

        const tableRows = filteredResults.map(r => `
            <tr>
                <td>${formatDate(r.transaction.date)}</td>
                <td>${r.transaction.cleanedDescription || r.transaction.description}</td>
                <td>${formatCurrency(r.transaction.amount, language)}</td>
                <td>${r.church.name}</td>
                <td>${r.contributor?.cleanedName || '---'}</td>
                <td>${r.status}</td>
            </tr>
        `).join('');

        printWindow.document.write(`
            <html>
                <head>
                    <title>${t('search.title')}</title>
                    <style>
                        body { font-family: sans-serif; }
                        table { width: 100%; border-collapse: collapse; }
                        th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
                        th { background-color: #f2f2f2; }
                    </style>
                </head>
                <body>
                    <h1>${t('search.title')}</h1>
                    <h3>${t('search.summaryTitle')}</h3>
                    <p>${t('search.totalTransactions')}: ${summary.totalCount}</p>
                    <p>${t('search.income')}: ${formatCurrency(summary.income, language)}</p>
                    <p>${t('search.expenses')}: ${formatCurrency(summary.expenses, language)}</p>
                    <hr/>
                    <table>
                        <thead>
                            <tr>
                                <th>${t('table.date')}</th>
                                <th>${t('table.description')}</th>
                                <th>${t('table.amount')}</th>
                                <th>${t('table.church')}</th>
                                <th>${t('table.contributor')}</th>
                                <th>${t('table.status')}</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${tableRows}
                        </tbody>
                    </table>
                </body>
            </html>
        `);
        printWindow.document.close();
        printWindow.print();
    };

    // UNIFIED BUTTON COMPONENT
    const UnifiedButton = ({ 
        onClick, 
        icon: Icon, 
        label, 
        badgeCount,
        isActive,
        isLast,
        variant = 'default'
    }: { 
        onClick: () => void, 
        icon: any, 
        label: string, 
        badgeCount?: number,
        isActive?: boolean,
        isLast?: boolean,
        variant?: 'default' | 'primary' | 'success' | 'danger' | 'warning' | 'info' | 'violet'
    }) => {
        const variants = {
            default: { icon: 'text-slate-300', activeBg: 'bg-white/20', hoverBg: 'hover:bg-white/10' },
            primary: { icon: 'text-blue-400', activeBg: 'bg-blue-500/30', hoverBg: 'hover:bg-blue-500/20' }, 
            success: { icon: 'text-emerald-400', activeBg: 'bg-emerald-500/30', hoverBg: 'hover:bg-emerald-500/20' }, 
            danger: { icon: 'text-rose-400', activeBg: 'bg-rose-500/30', hoverBg: 'hover:bg-rose-500/20' }, 
            warning: { icon: 'text-amber-400', activeBg: 'bg-amber-500/30', hoverBg: 'hover:bg-amber-500/20' }, 
            info: { icon: 'text-cyan-400', activeBg: 'bg-cyan-500/30', hoverBg: 'hover:bg-cyan-500/20' }, 
            violet: { icon: 'text-purple-400', activeBg: 'bg-purple-500/30', hoverBg: 'hover:bg-purple-500/20' }, 
        };

        const v = variants[variant];

        return (
            <>
                <button 
                    onClick={onClick}
                    className={`
                        relative flex-1 flex items-center justify-center gap-2 px-4 h-full text-[10px] font-bold uppercase transition-all outline-none group
                        ${isActive 
                            ? `text-white ${v.activeBg} shadow-[0_0_15px_rgba(0,0,0,0.3)]` 
                            : `text-slate-300 ${v.hoverBg} hover:text-white`
                        }
                    `}
                >
                    <Icon className={`w-3.5 h-3.5 ${isActive ? 'text-white drop-shadow-[0_0_5px_rgba(255,255,255,0.5)]' : v.icon}`} />
                    <span className="hidden sm:inline">{label}</span>
                    {badgeCount !== undefined && badgeCount > 0 && (
                        <span className="ml-1 bg-red-500 px-1.5 py-0.5 rounded-full text-[9px] leading-none text-white font-bold">
                            {badgeCount}
                        </span>
                    )}
                </button>
                {!isLast && <div className="w-px h-3 bg-white/10 self-center"></div>}
            </>
        );
    };

    if (allHistoricalResults.length === 0) {
        return (
            <div className="flex-1 flex items-center justify-center">
                <EmptyState icon={<SearchIcon className="w-12 h-12 text-brand-blue dark:text-blue-400" />} title={t('empty.search.title')} message={t('empty.search.message')} action={{ text: t('empty.dashboard.saved.action'), onClick: () => setActiveView('upload') }} />
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full animate-fade-in gap-2 pb-1">
            <div className="flex-shrink-0 flex items-center justify-between gap-4 px-1 mt-1 min-h-[40px]">
                <h2 className="text-xl font-black text-brand-deep dark:text-white tracking-tight leading-none whitespace-nowrap">{t('search.title')}</h2>

                {/* UNIFIED COMMAND CAPSULE */}
                <div className="flex items-center h-9 bg-gradient-to-r from-blue-600 via-[#051024] to-blue-600 rounded-full shadow-lg border border-white/20 overflow-hidden p-0.5">
                     <UnifiedButton 
                        onClick={openSearchFilters}
                        icon={AdjustmentsHorizontalIcon}
                        label={t('search.filters')}
                        badgeCount={activeFilterCount}
                        variant="primary"
                     />
                     <UnifiedButton 
                        onClick={handlePrint}
                        icon={PrinterIcon}
                        label={t('common.print')}
                        variant="info"
                     />
                     <UnifiedButton 
                        onClick={handleSave}
                        icon={FloppyDiskIcon}
                        label={t('common.save')}
                        isLast={true}
                        variant="success"
                     />
                </div>
            </div>

             <div className="bg-white dark:bg-slate-800 p-3 rounded-2xl shadow-card border border-slate-100 dark:border-slate-700 flex-shrink-0 flex gap-4 items-end">
                {/* ... (Restante do header de busca mantido) ... */}
                {/* Scope Selector - Compacto */}
                <div className="w-1/3 min-w-[200px]">
                    <label htmlFor="search-scope" className="block text-[8px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-1 ml-1">Origem</label>
                    <div className="relative">
                        <CircleStackIcon className="w-3.5 h-3.5 text-slate-400 absolute top-1/2 left-2.5 -translate-y-1/2 pointer-events-none"/>
                        <select
                            id="search-scope"
                            value={searchFilters.reportId || ''}
                            onChange={(e) => setSearchFilters(prev => ({ ...prev, reportId: e.target.value || null }))}
                            className="pl-8 pr-6 py-1.5 block w-full rounded-lg border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-200 text-xs font-medium shadow-sm focus:border-brand-blue focus:ring-brand-blue transition-all cursor-pointer appearance-none outline-none"
                        >
                            <option value="">Todos ({allHistoricalResults.length} registros)</option>
                            {savedReports.map(report => (
                                <option key={report.id} value={report.id}>
                                    {report.name} ({report.recordCount})
                                </option>
                            ))}
                        </select>
                    </div>
                </div>

                <div className="flex-grow">
                    <label htmlFor="search-query" className="block text-[8px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest mb-1 ml-1">{t('search.nameDesc')}</label>
                    <div className="relative">
                        <SearchIcon className="w-3.5 h-3.5 text-brand-blue absolute top-1/2 left-2.5 -translate-y-1/2"/>
                        <input 
                            type="text" 
                            id="search-query" 
                            value={query} 
                            onChange={e => setQuery(e.target.value)} 
                            placeholder={t('search.nameDescPlaceholder')} 
                            className="pl-8 py-1.5 block w-full rounded-lg border-slate-200 dark:border-slate-600 bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-200 text-xs font-medium shadow-sm focus:border-brand-blue focus:ring-brand-blue transition-all outline-none"
                        />
                    </div>
                </div>
            </div>

            { (query || activeFilterCount > 0) && (
                <div className="flex-shrink-0 bg-white dark:bg-slate-800 p-2 rounded-2xl shadow-card border border-slate-100 dark:border-slate-700 animate-fade-in-up">
                    <div className="grid grid-cols-4 gap-2">
                        <div className="px-3 py-1.5 bg-slate-50 dark:bg-slate-700/30 rounded-xl border border-slate-100 dark:border-slate-700/50 flex justify-between items-center">
                            <p className="text-[9px] font-bold text-slate-500 dark:text-slate-400 uppercase">{t('search.totalTransactions')}</p>
                            <p className="font-black text-sm text-slate-900 dark:text-slate-100">{summary.totalCount}</p>
                        </div>
                        <div className="px-3 py-1.5 bg-emerald-50 dark:bg-emerald-900/20 rounded-xl border border-emerald-100 dark:border-emerald-800/30 flex justify-between items-center">
                            <p className="text-[9px] font-bold text-emerald-600 dark:text-emerald-400 uppercase">{t('search.income')}</p>
                            <p className="font-black text-sm text-emerald-700 dark:text-emerald-300">{formatCurrency(summary.income, language)}</p>
                        </div>
                        <div className="px-3 py-1.5 bg-red-50 dark:bg-red-900/20 rounded-xl border border-red-100 dark:border-red-800/30 flex justify-between items-center">
                            <p className="text-[9px] font-bold text-red-600 dark:text-red-400 uppercase">{t('search.expenses')}</p>
                            <p className="font-black text-sm text-red-700 dark:text-red-300">{formatCurrency(summary.expenses, language)}</p>
                        </div>
                        <div className="px-3 py-1.5 bg-slate-50 dark:bg-slate-700/30 rounded-xl border border-slate-100 dark:border-slate-700/50 flex justify-between items-center">
                             <div className="flex items-center gap-1">
                                <CheckCircleIcon className="w-3 h-3 text-emerald-500"/>
                                <span className="text-[9px] font-bold text-slate-600 dark:text-slate-300 uppercase">{summary.identified}</span>
                            </div>
                             <div className="flex items-center gap-1">
                                <XCircleIcon className="w-3 h-3 text-amber-500"/>
                                <span className="text-[9px] font-bold text-slate-600 dark:text-slate-300 uppercase">{summary.unidentified}</span>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            <div className="flex-1 min-h-0 overflow-hidden flex flex-col">
                {filteredResults.length > 0 ? (
                     <ResultsTable 
                        results={paginatedResults} 
                        onManualIdentify={openManualIdentify} 
                        loadingAiId={loadingAiId} 
                        currentPage={currentPage} 
                        totalPages={totalPages} 
                        onPageChange={setCurrentPage} 
                    />
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-center p-8 text-slate-400 dark:text-slate-500 italic bg-white/50 dark:bg-slate-900/30 rounded-2xl border border-dashed border-slate-200 dark:border-slate-700">
                        <SearchIcon className="w-10 h-10 mb-2 opacity-50" />
                        <p>{t('search.noResults')}</p>
                    </div>
                )}
            </div>
        </div>
    );
};

import React, { useContext, useMemo, useState, memo, useEffect, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { EditableReportTable } from '../components/reports/EditableReportTable';
import { EmptyState } from '../components/EmptyState';
import { 
    DocumentDuplicateIcon, 
    PrinterIcon, 
    DocumentArrowDownIcon, 
    FloppyDiskIcon, 
    ChartBarIcon, 
    BuildingOfficeIcon, 
    ExclamationTriangleIcon, 
    CheckBadgeIcon, 
    BanknotesIcon
} from '../components/Icons';
import { formatCurrency, formatDate } from '../utils/formatters';
import { MatchResult, Language } from '../types';
import { parseDate, filterByUniversalQuery } from '../services/processingService';
import * as XLSX from 'xlsx';

type SortDirection = 'asc' | 'desc';
interface SortConfig {
    key: string;
    direction: SortDirection;
}

const getNestedValue = (obj: any, path: string) => {
    return path.split('.').reduce((o, key) => (o && o[key] != null ? o[key] : null), obj);
};

// Componente Compacto de Métricas (Design Clean)
const CompactMetricsBar: React.FC<{ metrics: any, language: Language, isExpense: boolean }> = ({ metrics, language, isExpense }) => {
    if (isExpense || !metrics) return null;

    return (
        <div className="flex items-center gap-2 text-[9px] font-medium text-slate-600 dark:text-slate-300 overflow-x-auto custom-scrollbar pb-0.5">
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 whitespace-nowrap">
                <span className="font-bold text-slate-700 dark:text-slate-200">Total:</span>
                <span className="text-slate-600 dark:text-slate-400">{metrics.total.quantity}</span>
                <span className="text-slate-300 dark:text-slate-600 mx-0.5">|</span>
                <span className="font-mono font-bold text-slate-900 dark:text-white">{formatCurrency(metrics.total.value, language)}</span>
            </div>
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-100 dark:border-emerald-800 whitespace-nowrap">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
                <span className="text-emerald-700 dark:text-emerald-400">Auto: {metrics.auto.quantity}</span>
                <span className="font-mono font-bold text-emerald-600 dark:text-emerald-500">({metrics.auto.percentage.toFixed(0)}%)</span>
            </div>
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 whitespace-nowrap">
                <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
                <span className="text-blue-700 dark:text-blue-400">Manual: {metrics.manual.quantity}</span>
                <span className="font-mono font-bold text-blue-600 dark:text-blue-500">({metrics.manual.percentage.toFixed(0)}%)</span>
            </div>
            {metrics.pending.quantity > 0 && (
                <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-md bg-amber-50 dark:bg-amber-900/20 border border-amber-100 dark:border-amber-800 whitespace-nowrap">
                    <ExclamationTriangleIcon className="w-3 h-3 text-amber-500" />
                    <span className="text-amber-700 dark:text-amber-400 font-bold">Pend: {metrics.pending.quantity}</span>
                    <span className="font-mono font-bold text-amber-600 dark:text-amber-500">({formatCurrency(metrics.pending.value, language)})</span>
                </div>
            )}
        </div>
    );
};

const ReportGroup: React.FC<{
    churchId: string;
    results: MatchResult[];
    reportType: 'income' | 'expenses';
    defaultOpen?: boolean;
}> = ({ churchId, results, reportType }) => {
    const {
        churches,
        updateReportData,
        searchFilters,
        openBulkManualIdentify,
        loadingAiId,
        openManualIdentify
    } = useContext(AppContext);
    const { t, language } = useTranslation();
    const [searchQuery] = useState(''); // Simplified: Remove local search if not used in UI or implement input
    const [sortConfig, setSortConfig] = useState<SortConfig | null>({ key: 'transaction.date', direction: 'desc' });

    const safeResults = useMemo(() => Array.isArray(results) ? results : [], [results]);

    const processedResults = useMemo(() => {
        let filteredData = [...safeResults];

        if (searchFilters.dateRange.start || searchFilters.dateRange.end) {
            const startDate = searchFilters.dateRange.start ? new Date(searchFilters.dateRange.start).getTime() : null;
            const endDate = searchFilters.dateRange.end ? new Date(searchFilters.dateRange.end).getTime() + 86400000 : null;
            filteredData = filteredData.filter(r => {
                const txDate = parseDate(r.transaction.date)?.getTime();
                if (!txDate) return false;
                if (startDate && txDate < startDate) return false;
                if (endDate && txDate >= endDate) return false;
                return true;
            });
        }

        const { operator, value1, value2 } = searchFilters.valueFilter;
        if (operator !== 'any' && value1 !== null) {
            filteredData = filteredData.filter(r => {
                const amount = Math.abs(r.transaction.amount);
                switch (operator) {
                    case 'exact': return amount === value1;
                    case 'gt': return amount > value1;
                    case 'lt': return amount < value1;
                    case 'between': return value2 !== null && amount >= value1 && amount <= value2;
                    default: return true;
                }
            });
        }

        if (searchFilters.reconciliationStatus !== 'all') {
            switch (searchFilters.reconciliationStatus) {
                case 'confirmed_any':
                    filteredData = filteredData.filter(r => r.status === 'IDENTIFICADO');
                    break;
                case 'unconfirmed':
                    filteredData = filteredData.filter(r => r.status === 'NÃO IDENTIFICADO');
                    break;
                case 'confirmed_auto':
                    filteredData = filteredData.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
                    break;
                case 'confirmed_manual':
                    filteredData = filteredData.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
                    break;
            }
        }

        if (searchFilters.filterBy === 'church' && searchFilters.churchIds.length > 0) {
            filteredData = filteredData.filter(r => searchFilters.churchIds.includes(r.church.id));
        }

        if (searchFilters.filterBy === 'contributor' && searchFilters.contributorName.trim()) {
             filteredData = filteredData.filter(r => filterByUniversalQuery(r, searchFilters.contributorName));
        }

        if (searchQuery.trim()) {
            filteredData = filteredData.filter(r => filterByUniversalQuery(r, searchQuery));
        }

        if (sortConfig !== null) {
            filteredData.sort((a, b) => {
                const aValue = getNestedValue(a, sortConfig.key);
                const bValue = getNestedValue(b, sortConfig.key);
                if (sortConfig.key === 'transaction.date' || (sortConfig.key.includes('date'))) {
                    const dateA = parseDate(aValue)?.getTime() || 0;
                    const dateB = parseDate(bValue)?.getTime() || 0;
                    return sortConfig.direction === 'asc' ? dateA - dateB : dateB - dateA;
                }
                if (aValue === null || aValue === undefined) return 1;
                if (bValue === null || bValue === undefined) return -1;
                if (typeof aValue === 'number' && typeof bValue === 'number') {
                     return sortConfig.direction === 'asc' ? aValue - bValue : bValue - aValue;
                }
                if (typeof aValue === 'string' && typeof bValue === 'string') {
                    return sortConfig.direction === 'asc' ? aValue.localeCompare(bValue) : bValue.localeCompare(aValue);
                }
                return 0;
            });
        }
        return filteredData;
    }, [safeResults, searchQuery, sortConfig, searchFilters]);

    const handleSort = (key: string) => {
        let direction: SortDirection = 'asc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
    };

    const summaryMetrics = useMemo(() => {
        if (reportType === 'expenses') return null;

        const identifiedRows = processedResults.filter(r => r.status === 'IDENTIFICADO');
        const autoConfirmed = identifiedRows.filter(r => r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod);
        const manualConfirmed = identifiedRows.filter(r => r.matchMethod === 'MANUAL' || r.matchMethod === 'AI');
        const bankPendingRows = processedResults.filter(r => r.status === 'NÃO IDENTIFICADO');
        const listPendingRows = processedResults.filter(r => r.status === 'PENDENTE');
        const totalCount = processedResults.length;

        const getRowValue = (r: MatchResult) => {
            if (Math.abs(r.transaction.amount) > 0) return r.transaction.amount;
            return r.contributorAmount || 0;
        };

        const valAuto = autoConfirmed.reduce((sum, r) => sum + getRowValue(r), 0);
        const valManual = manualConfirmed.reduce((sum, r) => sum + getRowValue(r), 0);
        const valBankPending = bankPendingRows.reduce((sum, r) => sum + r.transaction.amount, 0);
        const valListPending = listPendingRows.reduce((sum, r) => sum + (r.contributorAmount || 0), 0);
        const totalPendingValue = valBankPending + valListPending;
        const totalValue = valAuto + valManual + totalPendingValue;
        const totalPendingCount = bankPendingRows.length + listPendingRows.length;

        return {
            auto: { quantity: autoConfirmed.length, value: valAuto, percentage: totalCount > 0 ? (autoConfirmed.length / totalCount) * 100 : 0 },
            manual: { quantity: manualConfirmed.length, value: valManual, percentage: totalCount > 0 ? (manualConfirmed.length / totalCount) * 100 : 0 },
            pending: { quantity: totalPendingCount, value: totalPendingValue, percentage: totalCount > 0 ? (totalPendingCount / totalCount) * 100 : 0 },
            total: { quantity: totalCount, value: totalValue, percentage: 100 }
        };
    }, [processedResults, reportType]);

    const simpleTotalValue = summaryMetrics ? summaryMetrics.total.value : processedResults.reduce((sum, r) => {
         if (reportType === 'income') {
             return sum + (Math.abs(r.transaction.amount) > 0 ? r.transaction.amount : (r.contributorAmount || 0));
         }
         return sum + r.transaction.amount;
    }, 0);

    const getGroupName = (id: string): string => {
        if (id === 'unidentified') return t('reports.unidentifiedGroupTitle');
        if (id === 'all_expenses_group') return t('reports.expenseReportTitle');
        return churches.find(c => c.id === id)?.name || t('reports.unknownChurch');
    };

    const groupName = getGroupName(churchId);

    const handleBulkIdentify = () => {
        const transactions = processedResults.filter(r => r.status !== 'PENDENTE').map(r => r.transaction);
        openBulkManualIdentify(transactions);
    };

    // Handler para download Excel (mantido para compatibilidade, idealmente mover para utilitário)
    const handleDownload = () => {
        const wb = XLSX.utils.book_new();
        const wsData: any[][] = [
            [groupName],
            [`Gerado em: ${new Date().toLocaleString(language)}`],
            [`Registros: ${processedResults.length}`],
            [''],
            ['Data', reportType === 'income' ? 'Nome / Contribuinte' : 'Descrição', 'Tipo', 'Valor']
        ];

        processedResults.forEach(r => {
            const isPendingList = r.status === 'PENDENTE';
            const amount = isPendingList ? 0 : (reportType === 'income' ? (r.contributorAmount ?? r.transaction.amount) : r.transaction.amount);
            const mainName = reportType === 'income' ? (r.contributor?.cleanedName || r.contributor?.name || '---') : (r.transaction.cleanedDescription || r.transaction.description);
            const type = r.contributor?.contributionType || r.contributionType || r.transaction.contributionType || '---';

            wsData.push([formatDate(r.transaction.date), isPendingList ? `${mainName} (Não Localizado)` : mainName, type, amount]);
        });

        const ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = [{ wch: 12 }, { wch: 40 }, { wch: 15 }, { wch: 15 }];
        XLSX.utils.book_append_sheet(wb, ws, "Relatório");
        XLSX.writeFile(wb, `${groupName.replace(/[^a-z0-9]/gi, '_')}_${reportType}.xlsx`);
    };

    // Handler para impressão (mantido)
    const handlePrint = () => {
        const printWindow = window.open('', '_blank');
        if (!printWindow) return;

        const currentChurch = churches.find(c => c.id === churchId);
        const logoHtml = currentChurch?.logoUrl
            ? `<img src="${currentChurch.logoUrl}" style="max-height: 60px; max-width: 100px; object-fit: contain; margin-right: 15px;" />`
            : '';

        const tableRows = processedResults.map(r => {
            const isPendingList = r.status === 'PENDENTE';
            const amount = isPendingList ? 0 : (reportType === 'income' ? (r.contributorAmount ?? r.transaction.amount) : r.transaction.amount);
            const mainName = reportType === 'income' ? (r.contributor?.cleanedName || r.contributor?.name || '---') : (r.transaction.cleanedDescription || r.transaction.description);
            const type = r.contributor?.contributionType || r.contributionType || r.transaction.contributionType || '---';
            const formattedAmount = isPendingList ? `<span style="text-decoration: line-through; color: #94a3b8;">${formatCurrency(0, language)}</span>` : formatCurrency(amount, language);

            return `<tr><td style="font-family: monospace;">${formatDate(r.transaction.date)}</td><td>${mainName} ${isPendingList ? '<span style="font-size: 9px; color: red; font-style: italic;">(Não Localizado)</span>' : ''}</td><td>${type}</td><td style="text-align:right; font-family: monospace; font-weight: bold;">${formattedAmount}</td></tr>`;
        }).join('');

        const summaryHtml = summaryMetrics 
            ? `<div class="summary"><div class="summary-item"><span class="label">Total</span><span class="value">${summaryMetrics.total.quantity}</span><span style="font-size: 11px;">${formatCurrency(summaryMetrics.total.value, language)}</span></div></div>`
            : `<div class="summary"><div class="summary-item"><span class="label">Total</span><span class="value">${processedResults.length}</span></div><div class="summary-item"><span class="label">Valor</span><span class="value">${formatCurrency(simpleTotalValue, language)}</span></div></div>`;

        printWindow.document.write(`<html><head><title>${groupName}</title><style>body { font-family: 'Inter', sans-serif; padding: 40px; color: #1e293b; } .header { border-bottom: 3px solid #0052cc; padding-bottom: 15px; margin-bottom: 30px; display: flex; align-items: center; justify-content: space-between; } .header-left { display: flex; align-items: center; } h1 { margin: 0; font-size: 24px; font-weight: 800; text-transform: uppercase; } table { width: 100%; border-collapse: collapse; margin-top: 10px; } th { background-color: #f8fafc; border-bottom: 2px solid #e2e8f0; padding: 12px 10px; text-align: left; font-size: 10px; font-weight: 800; color: #475569; text-transform: uppercase; } td { padding: 12px 10px; border-bottom: 1px solid #f1f5f9; font-size: 12px; } .summary { margin-top: 30px; padding: 20px; background: #f8fafc; border-radius: 12px; display: flex; gap: 40px; } .summary-item { display: flex; flex-direction: column; } .label { font-size: 9px; font-weight: 800; color: #64748b; text-transform: uppercase; } .value { font-size: 16px; font-weight: 800; color: #0f172a; } @media print { body { padding: 0; } }</style></head><body><div class="header"><div class="header-left">${logoHtml}<div><h1>${groupName}</h1><div style="font-size: 12px; font-weight: 600; color: #0052cc;">Relatório de Conciliação</div></div></div></div>${summaryHtml}<table><thead><tr><th style="width: 15%;">Data</th><th style="width: 45%;">${reportType === 'income' ? 'Nome / Contribuinte' : 'Descrição'}</th><th style="width: 20%;">Tipo</th><th style="text-align:right; width: 20%;">Valor</th></tr></thead><tbody>${tableRows}</tbody></table></body></html>`);
        printWindow.document.close();
    };

    return (
        <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-card border border-slate-100 dark:border-slate-700 overflow-hidden flex flex-col mb-4">
            <div className="px-4 py-3 bg-white/50 dark:bg-slate-900/50 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center sticky top-0 z-20 backdrop-blur-sm">
                <div className="flex items-center gap-3">
                    {/* Header Group */}
                    <div className="flex items-center gap-2">
                        <div className={`p-1.5 rounded-lg ${reportType === 'income' ? 'bg-blue-50 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400' : 'bg-red-50 text-red-600 dark:bg-red-900/30 dark:text-red-400'}`}>
                            {reportType === 'income' ? <ChartBarIcon className="w-4 h-4"/> : <BanknotesIcon className="w-4 h-4"/>}
                        </div>
                        <div>
                            <h3 className="text-sm font-bold text-slate-800 dark:text-white leading-tight">{groupName}</h3>
                            <p className="text-[10px] text-slate-500 dark:text-slate-400">
                                {processedResults.length} registros • {formatCurrency(simpleTotalValue, language)}
                            </p>
                        </div>
                    </div>
                    {/* Compact Metrics */}
                    <div className="hidden md:block">
                        <CompactMetricsBar metrics={summaryMetrics} language={language} isExpense={reportType === 'expenses'} />
                    </div>
                </div>

                <div className="flex items-center gap-1.5">
                    {/* Botão Identificar em Massa (Apenas para Não Identificados) */}
                    {churchId === 'unidentified' && (
                        <button onClick={handleBulkIdentify} className="p-1.5 rounded-lg text-white bg-indigo-600 hover:bg-indigo-700 shadow-sm transition-colors" title="Identificar em Massa">
                            <UserPlusIcon className="w-3.5 h-3.5" />
                        </button>
                    )}
                    <button onClick={handlePrint} className="p-1.5 rounded-lg text-slate-500 hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors" title="Imprimir">
                        <PrinterIcon className="w-3.5 h-3.5" />
                    </button>
                    <button onClick={handleDownload} className="p-1.5 rounded-lg text-emerald-600 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 transition-colors" title="Baixar Excel">
                        <DocumentArrowDownIcon className="w-3.5 h-3.5" />
                    </button>
                </div>
            </div>

            <EditableReportTable 
                data={processedResults}
                onRowChange={(updated) => updateReportData(updated, reportType)}
                reportType={reportType}
                sortConfig={sortConfig}
                onSort={handleSort}
                loadingAiId={loadingAiId}
                onEdit={(row) => openManualIdentify(row.transaction.id)}
            />
        </div>
    );
};

