        count?: number,
        isActive?: boolean,
        isLast?: boolean,
        variant?: 'default' | 'primary' | 'success' | 'danger' | 'warning'
    }) => {
        const variants = {
            default: { icon: 'text-slate-300', activeBg: 'bg-white/20', hoverBg: 'hover:bg-white/10' },
            primary: { icon: 'text-blue-400', activeBg: 'bg-blue-500/30', hoverBg: 'hover:bg-blue-500/20' }, 
            success: { icon: 'text-emerald-400', activeBg: 'bg-emerald-500/30', hoverBg: 'hover:bg-emerald-500/20' }, 
            danger: { icon: 'text-rose-400', activeBg: 'bg-rose-500/30', hoverBg: 'hover:bg-rose-500/20' }, 
            warning: { icon: 'text-amber-400', activeBg: 'bg-amber-500/30', hoverBg: 'hover:bg-amber-500/20' }, 
        };

        const v = variants[variant];

        return (
