                >
                    <Icon className={`w-3.5 h-3.5 ${isActive ? 'text-white drop-shadow-[0_0_5px_rgba(255,255,255,0.5)]' : v.icon}`} />
                    <span className="hidden sm:inline">{label}</span>
                    {count !== undefined && count > 0 && (
                        <span className={`
                            ml-1 px-1.5 py-0.5 rounded-full text-[9px] leading-none 
                            ${isActive ? 'bg-white/30 text-white' : 'bg-slate-900/50 text-slate-300 group-hover:bg-white/20 group-hover:text-white'}
