            </div>

            {activeTab === 'churches' && churchGroups.length > 0 && (
                <div className="flex items-center gap-1.5 overflow-x-auto pb-1 pt-0.5 custom-scrollbar min-h-[28px] px-1">
                    {churchGroups.map(([churchId, results]) => {
