                            <h4 className="text-xs font-black text-amber-900 dark:text-amber-100 uppercase tracking-wide mb-0.5 flex items-center gap-2">
                                {t('upload.support.title')}
                            </h4>
                            <p className="text-[10px] text-amber-800/90 dark:text-amber-200/90 leading-snug max-w-2xl font-bold line-clamp-1">
                                {t('upload.support.desc')}
                            </p>
                        </div>
                    </div>
                    <button 
