                    >
                        <WhatsAppIcon className="w-3.5 h-3.5 text-emerald-600 dark:text-emerald-500 group-hover/btn:scale-110 transition-transform" />
                        <span className="hidden sm:inline">{t('upload.support.action')}</span>
                    </button>
                </div>

                <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-4 min-h-0">

                    {/* BANK STATEMENTS COLUMN */}
