type AdminTab = 'settings' | 'users' | 'audit' | 'models';

const FIX_SQL = `
-- (SQL mantido inalterado)
`;

export const AdminView: React.FC = () => {
    // ... (Hooks e estados mantidos)
    const [activeTab, setActiveTab] = useState<AdminTab>('settings');
    const { user } = useAuth();
    const { showToast } = useUI();
    const { t } = useTranslation();
    const [showSqlModal, setShowSqlModal] = useState(false);
    const [showDiagModal, setShowDiagModal] = useState(false);
    const [diagResult, setDiagResult] = useState<any>(null);
    const [isLoadingDiag, setIsLoadingDiag] = useState(false);

    const handleSync = () => {
        showToast("Dados sincronizados com sucesso.", "success");
    };

    const copySql = () => {
        navigator.clipboard.writeText(FIX_SQL);
        showToast("SQL copiado! Execute no Supabase SQL Editor.", "success");
    };

    const runDiagnostics = async () => {
        setIsLoadingDiag(true);
        setShowDiagModal(true);

        const results: any = {
            apiStatus: 'ONLINE',
            geminiKey: !!process.env.API_KEY,
            supabaseStatus: 'CHECKING',
            tableModelsStatus: 'CHECKING',
            authStatus: !!user
        };

        try {
            const { error } = await supabase.from('profiles').select('count').limit(1);
            results.supabaseStatus = error ? 'ERROR' : 'CONNECTED';
            if (error) results.supabaseError = error.message;

            const { error: tableError } = await supabase.from('file_models').select('count').limit(1);
            results.tableModelsStatus = tableError ? 'MISSING' : 'OK';

        } catch (e) {
            results.supabaseStatus = 'FAILED';
        }

        setTimeout(() => {
            setDiagResult(results);
            setIsLoadingDiag(false);
        }, 800);
    };

    // UNIFIED BUTTON COMPONENT
    const UnifiedButton = ({ 
        onClick, 
        icon: Icon, 
        label, 
        isActive,
        isLast,
        variant = 'default'
    }: { 
        onClick: () => void, 
        icon: any, 
        label: string, 
        isActive?: boolean,
        isLast?: boolean,
        variant?: 'default' | 'primary' | 'success' | 'danger' | 'warning' | 'info' | 'violet'
    }) => {
        const variants = {
            default: { icon: 'text-slate-300', activeBg: 'bg-white/20', hoverBg: 'hover:bg-white/10' },
            primary: { icon: 'text-blue-400', activeBg: 'bg-blue-500/30', hoverBg: 'hover:bg-blue-500/20' }, 
            success: { icon: 'text-emerald-400', activeBg: 'bg-emerald-500/30', hoverBg: 'hover:bg-emerald-500/20' }, 
            danger: { icon: 'text-rose-400', activeBg: 'bg-rose-500/30', hoverBg: 'hover:bg-rose-500/20' }, 
            warning: { icon: 'text-amber-400', activeBg: 'bg-amber-500/30', hoverBg: 'hover:bg-amber-500/20' }, 
            info: { icon: 'text-indigo-400', activeBg: 'bg-indigo-500/30', hoverBg: 'hover:bg-indigo-500/20' }, 
            violet: { icon: 'text-purple-400', activeBg: 'bg-purple-500/30', hoverBg: 'hover:bg-purple-500/20' }, 
        };

        const v = variants[variant];

        return (
            <>
                <button 
                    onClick={onClick}
                    className={`
                        relative flex-1 flex items-center justify-center gap-2 px-6 h-full text-[10px] font-bold uppercase transition-all outline-none group whitespace-nowrap
                        ${isActive 
                            ? `text-white ${v.activeBg} shadow-[0_0_15px_rgba(0,0,0,0.3)]` 
                            : `text-slate-300 ${v.hoverBg} hover:text-white`
                        }
                    `}
                >
                    <Icon className={`w-3.5 h-3.5 ${isActive ? 'text-white drop-shadow-[0_0_5px_rgba(255,255,255,0.5)]' : v.icon}`} />
                    <span className="hidden sm:inline">{label}</span>
                </button>
                {!isLast && <div className="w-px h-3 bg-white/10 self-center"></div>}
            </>
        );
    };

    return (
        <div className="flex flex-col h-full animate-fade-in gap-3 pb-2">
            <div className="flex flex-col xl:flex-row xl:items-center justify-between gap-3 flex-shrink-0 px-1">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-slate-100 dark:bg-slate-800 rounded-xl">
                        <ShieldCheckIcon className="w-5 h-5 text-slate-700 dark:text-slate-200" />
                    </div>
                    <div>
                        <h2 className="text-xl font-black text-brand-deep dark:text-white tracking-tight leading-none">{t('admin.title')}</h2>
                        <p className="text-slate-500 dark:text-slate-400 text-[10px] mt-0.5">Diagnóstico e Gestão do Sistema</p>
                    </div>
                </div>

                <div className="flex flex-col md:flex-row gap-2 md:items-center">

                    {/* UNIFIED COMMAND CAPSULE */}
