                </div>
            </div>

            { (query || activeFilterCount > 0) && (
                <div className="flex-shrink-0 bg-white dark:bg-slate-800 p-2 rounded-2xl shadow-card border border-slate-100 dark:border-slate-700 animate-fade-in-up">
