        getExportData().forEach(item => {
            wsData.push([
                item.pos.toString(),
                item.name,
                item.income.toLocaleString('pt-BR', { minimumFractionDigits: 2 }),
                item.expense.toLocaleString('pt-BR', { minimumFractionDigits: 2 }),
                item.balance.toLocaleString('pt-BR', { minimumFractionDigits: 2 }),
                item.count.toString()
