                     <UnifiedButton 
                        onClick={() => setActiveTab('preferences')}
                        isActive={activeTab === 'preferences'}
                        label={t('settings.tabPreferences')} 
                        icon={WrenchScrewdriverIcon} 
                        variant="primary"
